class Solution:
    def distributeCandies(self, n: int, limit: int) -> int:
        # Count triples (a,b,c) with a+b+c=n and each <= limit
        ans = 0
        for a in range(0, min(limit, n) + 1):
            for b in range(0, min(limit, n - a) + 1):
                c = n - a - b
                if 0 <= c <= limit:
                    ans += 1
        return ans
```

